/* 4. Collapsible Filter Styles */
.filter-component {
  width: 100%;
}

.btn-filter-toggle {
  width: 100%;
  padding: 12px 16px;
  background-color: #f1f5f9;
  border: 1px solid #cbd5e1;
  border-radius: 10px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  cursor: pointer;
  font-weight: 600;
}

.icon-filter {
  width: 18px; height: 18px; fill: currentColor;
}

.filter-options-panel {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.3s ease;
}

.filter-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 8px;
  padding-top: 10px;
}

.filter-tag {
  padding: 10px;
  background-color: #ffffff;
  border: 1.5px solid #e2e8f0;
  border-radius: 8px;
  text-align: center;
  font-size: 13px;
  cursor: pointer;
  transition: all 0.2s ease;
}

.filter-tag.selected {
  border-color: #6366f1;
  background-color: rgba(99, 102, 241, 0.05);
  color: #6366f1;
  font-weight: 700;
}
